{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No requirement[4][6]",
    "asset_limits": "No requirement; not applicable[4][6]",
    "other_requirements": ["Must be a resident of a long-term care (LTC) facility in California, such as skilled nursing facilities, intermediate care facilities, or residential care facilities for the elderly (RCFEs). Applies regardless of age, including younger adults with disabilities[4][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including: investigating complaints about day-to-day care, health, safety, personal preferences; addressing violations of residents' rights or dignity; physical, verbal, mental, or financial abuse; poor quality of care; dietary concerns; medical care, therapy, rehabilitation; Medicare/Medi-Cal issues; improper transfer/discharge; inappropriate restraints. Ombudsman representatives review and investigate reports of abuse/neglect, follow resident wishes (or those of their representatives), conduct unannounced facility visits, and resolve issues confidentially[4][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Call local Ombudsman program (statewide 24/7 CRISISline available via state office; example San Diego: 800-640-4661[5][6])", "Contact local program office in person or by email (e.g., San Diego: 5560 Overland Ave., Ste 310, San Diego, CA 92123[5])", "No specific online application form; contact local program directly for assistance[4][6]"],
    "processing_time": "Immediate response to complaints; no formal processing time as services are provided on-demand by representatives[4][6]",
    "waitlist": null,
    "forms": ["No specific application forms required; families/residents contact Ombudsman directly to report issues or seek assistance[4]"],
    "documents": ["No documents needed to request services; provide details of the resident's situation, facility name, and specific concerns. Ombudsman handles investigation confidentially[4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services limited to residents of licensed LTC facilities (1,189 skilled nursing/intermediate care + 7,798 RCFEs)[6]",
    "regional_variations": "Administered by 35 local Ombudsman programs overseen by the state Office of the State Long-Term Care Ombudsman. Local programs handle services with potential differences in contact points, office locations, and coordinators, but core services uniform statewide[4][6]",
    "offices_or_providers": ["35 local programs throughout California; contact via California Department of Aging for local office[6]"]
  },
  "official_source": "https://aging.ca.gov/Programs_and_Services/Long-Term_Care_Ombudsman/[4]",
  "gotchas": ["This is not a benefits/payment program with income/asset tests—it's free advocacy for LTC residents only; cannot assist those not in licensed facilities[4][6]", "Services are complaint-driven or issue-specific, not ongoing personal care; focuses on rights protection and resolution[4][5]", "Families can contact on behalf of residents, but Ombudsman prioritizes resident's expressed wishes[4]", "Not for facility staff/volunteers (separate certification process); public-facing for residents/families[1][2]"],
  "data_shape_notes": "no income test; available only to residents of licensed LTC facilities statewide via 35 local programs; advocacy services on-demand, not tiered or quantified by hours/dollars"
}
